generated_oml:
// C3: Physical sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder attached directly to the permanent magnetic synchronous motor"
    DTDFVocab:producedData MotorEncoderData
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder mounted on the gearwheel gearbox"
    DTDFVocab:producedData GearboxEncoderData
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring electrical current of the motor"
    DTDFVocab:producedData MotorCurrentData
]

// C4: Data transmitted
instance MotorEncoderData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C8: Data
instance CurrentMeasuredData : DTDFVocab:Data [
    base:desc "Measured motor current obtained from MotorCurrentSensor"
    DTDFVocab:fromData MotorCurrentData
]

instance TorqueMeasuredData : DTDFVocab:Data [
    base:desc "Computed torque from encoder data of motor and gearbox"
    DTDFVocab:fromData MotorEncoderData, GearboxEncoderData
]

instance VelocityMeasuredData : DTDFVocab:Data [
    base:desc "Computed angular velocity from encoder data"
    DTDFVocab:fromData MotorEncoderData, GearboxEncoderData
]

instance AccelerationMeasuredData : DTDFVocab:Data [
    base:desc "Computed angular acceleration from encoder data"
    DTDFVocab:fromData MotorEncoderData, GearboxEncoderData
]

instance TorqueSimulatedData : DTDFVocab:Data [
    base:desc "Simulated torque from Simulink motor and gearbox model"
]

instance VelocitySimulatedData : DTDFVocab:Data [
    base:desc "Simulated velocity from Simulink motor and gearbox model"
]

instance AccelerationSimulatedData : DTDFVocab:Data [
    base:desc "Simulated acceleration from Simulink motor and gearbox model"
]

// C11: Enablers
instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker responsible for ingesting sensor streams from the robot axis"
    DTDFVocab:enables RealTimeDataAggregationService
]

instance SimulinkSimEnabler : DTDFVocab:Enabler [
    base:desc "Simulink simulation framework executing the data calculation model"
    DTDFVocab:enables FrictionEstimationService, PerformanceMonitoringService
]

instance WebDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web dashboard hosting platform enabling real-time visualization via HTML/JavaScript"
    DTDFVocab:enables VisualizationDashboardService
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell linking metadata to the digital twin"
    DTDFVocab:enables PerformanceMonitoringService
]

// C10: Models/Data
instance StructuralSysMLModel : DTDFVocab:Model [
    base:desc "Structural SysML model of the robot axis used for engineering design"
    DTDFVocab:inputTo MQTTBrokerEnabler
]

instance DataCalcModelSimulink : DTDFVocab:Model [
    base:desc "Simulink data calculation model simulating motor, gearwheel, and gearbox dynamics"
    DTDFVocab:inputTo SimulinkSimEnabler
]

// C6: Services
instance RealTimeDataAggregationService : DTDFVocab:Service [
    base:desc "Real-time aggregation of sensor data and transmission to visualization dashboards"
    DTDFVocab:provides AggregatedDataInsight
]

instance FrictionEstimationService : DTDFVocab:Service [
    base:desc "Continuous friction estimation for the first robot axis using simulation data"
    DTDFVocab:provides FrictionParameterExtractionInsight
]

instance VisualizationDashboardService : DTDFVocab:Service [
    base:desc "Live plotting dashboard for measured and simulated signals of the robot axis"
    DTDFVocab:provides LivePlotsInsight
]

instance PerformanceMonitoringService : DTDFVocab:Service [
    base:desc "Performance monitoring supporting maintenance scheduling and controller updates"
    DTDFVocab:provides MaintenanceScheduleInsight, PerformanceImprovementInsight, UpdateControllerParametersAction, ScheduleMaintenanceAction
]

// C17: Insights/Actions
instance AggregatedDataInsight : DTDFVocab:Insight [
    base:desc "Insight on aggregated real-time data streams from the robot axis sensors"
]

instance FrictionParameterExtractionInsight : DTDFVocab:Insight [
    base:desc "Insight on extracted friction parameters over time for the first axis"
]

instance LivePlotsInsight : DTDFVocab:Insight [
    base:desc "Insight into live plotted data of measured versus simulated signals"
]

instance MaintenanceScheduleInsight : DTDFVocab:Insight [
    base:desc "Insight to schedule maintenance based on friction trends"
]

instance PerformanceImprovementInsight : DTDFVocab:Insight [
    base:desc "Insight on improving robot performance through updated controller settings"
]

instance UpdateControllerParametersAction : DTDFVocab:Action [
    base:desc "Automatic action updating controller parameters for improved motor performance"
    DTDFVocab:IsAutomatic true
]

instance ScheduleMaintenanceAction : DTDFVocab:Action [
    base:desc "Automatic action scheduling maintenance based on friction data"
    DTDFVocab:IsAutomatic true
]

// C17: Components
instance PermanentMagneticSynchronousMotor : DTDFVocab:Component [
    base:desc "Permanent magnetic synchronous motor driving the first robot axis"
]

instance GearwheelGearbox : DTDFVocab:Component [
    base:desc "Gearwheel gearbox providing mechanical reduction for the first axis"
]

instance CycloidalGearbox : DTDFVocab:Component [
    base:desc "Cycloidal gearbox following the gearwheel gearbox on the first axis"
]

// C16: Environment
instance RobotAxisEnvironment : DTDFVocab:Environment [
    base:contains PermanentMagneticSynchronousMotor, GearwheelGearbox, CycloidalGearbox, MotorEncoder, GearboxEncoder, MotorCurrentSensor, MQTTBrokerEnabler, SimulinkSimEnabler, WebDashboardEnabler, AssetAdministrationShellEnabler
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time, continuous data acquisition and processing; the digital shadow is updated in sync with the robot’s sampling period (typically in the kHz range of the CNC controller)."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow comprised of a processing component (Simulink simulation models), data‑calculation models (friction models), data traces (measured and simulated), an AAS for asset description, and a dashboard for visualization; all orchestrated by a central controller."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design (structural SysML model of the axis), Simulation (Simulink models of motor and gearbox), Deployment (integration of AAS and dashboard), Operation (real‑time friction identification and model update while robot runs)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "White‑box friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre) combined with black‑box identification; verification through traceability of data points back to raw sensor streams; continuous comparison of measured vs simulated outputs; uncertainty from unmodelled temperature or wear effects."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "One‑way MQTT communication from robot PLC/CNC controller to the digital shadow; messages contain current, encoder positions; timestamps may be omitted for simplification; no reverse channel specified."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML, UML class diagrams, Asset Administration Shell (AAS), MQTT protocol; adherence to IEC 61360 for asset description."
]
